// Convert response array -> items
const arr = Array.isArray($json) ? $json : ($json.body ?? $json);
if (!Array.isArray(arr)) throw new Error('Unexpected GitHub response shape');
return arr.filter(r => !r.fork).map(r => ({ json: {
  repo: r.name,
  full_name: r.full_name,
  api_url: r.url,
  html_url: r.html_url
}}));

// Normalize response. Do NOT persist any secret literals.
const repo = $item(0).$node['Split Array'].json.repo;
const fullName = $item(0).$node['Split Array'].json.full_name;
const repoUrl = $item(0).$node['Split Array'].json.html_url;

const statusCode = $json.statusCode ?? null;
const body = $json.body ?? $json;

// When secret scanning isn't enabled/available, GitHub returns 404/403.
if (statusCode === 404 || (body && body.message === 'Not Found')) {
  return [{ json: { repo, full_name: fullName, repo_url: repoUrl, secret_alerts_open: 0, secret_scanning: 'not_enabled', checked_at: new Date().toISOString(), notes: '' } }];
}
if (statusCode === 403 || (body && body.message && String(body.message).includes('forbidden'))) {
  return [{ json: { repo, full_name: fullName, repo_url: repoUrl, secret_alerts_open: 0, secret_scanning: 'forbidden', checked_at: new Date().toISOString(), notes: 'Check token scopes: repo or security_events (and repo settings).' } }];
}

const alerts = Array.isArray(body) ? body : [];
const types = new Set();
const urls = [];
for (const a of alerts) {
  if (a?.secret_type_display_name) types.add(a.secret_type_display_name);
  if (a?.html_url) urls.push(a.html_url);
}

return [{ json: {
  repo,
  full_name: fullName,
  repo_url: repoUrl,
  secret_alerts_open: alerts.length,
  secret_scanning: 'enabled',
  secret_types: Array.from(types).slice(0, 20).join(', '),
  alert_urls: urls.slice(0, 10).join(' '),
  checked_at: new Date().toISOString(),
  notes: alerts.length > 0 ? 'Review in GitHub Security tab (do not paste secrets in Sheets).' : ''
}}];
